import React, { useState } from 'react';

const App = () => {
  const [messages, setMessages] = useState([
    { username: 'John Doe', message: 'Hello!' },
    { username: 'Jane Doe', message: 'Hi!' },
    { username: 'John Doe', message: 'How are you?' }
  ]);
  const [newMessage, setNewMessage] = useState('');

  const handleInputChange = (event) => {
    setNewMessage(event.target.value);
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    setMessages([...messages, { username: 'John Doe', message: newMessage }]);
    setNewMessage('');
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="max-w-md bg-white p-4 rounded shadow">
        <span className="text-2xl font-bold">John Doe</span>
        <div className="mt-4">
          {messages.map((message, index) => (
            <div key={index} className="mb-2"><span className="mr-2 text-gray-400">{message.username}</span>{message.message}</div>
          ))}
        </div>
        <form onSubmit={handleSubmit} className="mt-4">
          <input
            type="text"
            value={newMessage}
            onChange={handleInputChange}
            placeholder="Type your message"
            className="w-full p-2 text-gray-700 focus:outline-none focus:ring focus:border-blue-500"
          />
          <button
            type="submit"
            className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
          >Send Message</button>
        </form>
      </div>
    </div>
  );
};

export default App;
